import ldap

def search_users_by_username(username):
    # Connect to the LDAP server
    ldap_conn = ldap.initialize('ldap://localhost')
    ldap_conn.bind()

    # Define the search filter
    search_filter = f'(&(objectClass=person)(cn={username}))'

    # Search for users with the given username
    search_results = ldap_conn.search_s('dc=example,dc=com', search_filter)

    # Return the results
    return search_results